It is amazing how by telling the issue to someone else you figure it out half of the times

```
@decor()
def func(*args):
    pass


class decor(object):
    INSTANCES_PATHS = list()

    def __init__(self):
        pass

    def __call__(self, wrapped):
        self.INSTANCE_PATHS.append(wrapped.__module__ + ',' + wrapped.__name__)
        return self._decor(wrapped)

    @wrapt.decorate
    def _decor(self, instance, args, kwargs):
        return wrapped(*args, **kwargs)
```

